<template>
  <div>
    <input type="button" id="" value="拍照并显示" @click="takePhoto()" />
    <input type="button" id="" value="上传" @click="uploadFile()" />
    <input
      type="button"
      id=""
      value="扫描二维码"
      @click="executeGoToScanPager()"
    />
    <img id="m-photo" src="" style="width: 100%; display: none" />
    <p id="m-photo-url"></p>
  </div>
</template>

<script>
export default {
  name: "testerweima", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      dataProps: "",
    };
  },
  computed: {},
  created() {},
  mounted() {},
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    takePhoto() {
      if (!deviceReady) {
        //执行到这边表示cordova环境没有准备好
        return;
      }
      //使用这边调用可以获取图像URL[和下面的只能调用一个方法]
      navigator.camera.getPicture(this.onSuccess, this.onError, this.getCameraOptions());
    },

    getCameraOptions() {
      var cameraOptions = {
        quality: 50,
        destinationType: navigator.camera.DestinationType.FILE_URI,
        sourceType: navigator.camera.PictureSourceType.CAMERA,
        targetWidth: 0,
        targetHeight: 0,
        //allowEdit : true,
        encodingType: Camera.EncodingType.JPEG,
        saveToPhotoAlbum: true,
      };
      return cameraOptions;
    },

    onSuccess(imageURI) {
      alert("onSuccess() imageURI:" + imageURI);
      //从这边返回数据
      $("#m-photo").attr("src", imageURI);
      $("#m-photo").css("display", "block");
      $("#m-photo-url").html(imageURI);
    },
    //参数为string类型
    onError(cameraError) {
      alert(cameraError);
    },
    // 上传文件到服务器
    uploadFile() {
      alert($("#m-photo-url").html());
      var ft = new FileTransfer();
      alert("FileTransfer");
      var path = $("#m-photo-url").html();
      var name = "hmx";
      ft.upload(
        path,
        "http://123.57.25.126/pms7.1_cvs/rest/setDGDWJHZP",
        function (result) {
          alert("Upload success: " + result.responseCode);
          alert(result.bytesSent + " bytes sent");
        },
        function (error) {
          alert("Error uploading file " + path + ": " + error.code);
        },
        {
          fileName: name,
        }
      );
    },

    //到扫描界面
    executeGoToScanPager() {
      console.log("executeGoToScanPager()-->start");
      if (!ready) {
        console.log("Cordova is not ready,return");
        return;
      }
      //获取平台信息[需要把这边获取的平台信息发送到服务器]
      var devicePlatform = device.platform;
      document.getElementById("list").innerHTML = "";
      //执行到这边表示cordova环境准备完成,在二维码扫描界面
      mam.navigator.forward.goToScanTwoDiemCode(successCallback, errorCallback);
      //执行成功回调
      //这边参数表示扫描成功后返回的字符串
      function successCallback(msg) {
        alert("11");
        document.getElementById("textarea").value = msg;
      }
      //执行失败回调[扫描失败，暂不退出界面未做处理]
      function errorCallback(msg) {
        alert("11");
        document.getElementById("list").innerHTML = "";
      }
    },
  },
};
</script>
